/* Application-wide confirmation and single-value input dialogs. */
.app-prompt-overlay {
  position: fixed;
  z-index: 1400;
  inset: 0;
  display: grid;
  place-items: center;
  padding: 24px;
  background: rgba(0, 0, 0, 0.42);
}

.app-prompt-dialog {
  width: min(480px, calc(100vw - 24px));
  max-height: calc(100dvh - 48px);
  display: flex;
  flex-direction: column;
  overflow: hidden;
  border: 1px solid var(--border);
  border-radius: 8px;
  background: var(--bg);
  color: var(--text);
  box-shadow: 0 18px 52px rgba(0, 0, 0, 0.3);
  animation: app-prompt-enter 150ms ease-out;
}

.app-prompt-content {
  min-height: 0;
  overflow: auto;
  padding: 20px;
}

.app-prompt-title {
  margin: 0;
  color: var(--text);
  font-size: 16px;
  font-weight: 700;
  line-height: 1.35;
}

.app-prompt-message {
  margin-top: 10px;
  color: var(--text-muted);
  font-size: 13px;
  line-height: 1.55;
  overflow-wrap: anywhere;
}

.app-prompt-input-wrap { margin-top: 14px; }

.app-prompt-input {
  width: 100%;
  min-width: 0;
  border: 1px solid var(--border);
  border-radius: 6px;
  background: var(--bg-panel);
  color: var(--text);
  font: inherit;
  padding: 9px 10px;
  outline: none;
}

.app-prompt-input:focus { border-color: var(--accent); box-shadow: 0 0 0 2px color-mix(in srgb, var(--accent) 20%, transparent); }
.app-prompt-input[aria-invalid="true"] { border-color: #dc2626; }
.app-prompt-error { margin-top: 6px; color: #dc2626; font-size: 12px; line-height: 1.4; }

.app-prompt-actions {
  display: flex;
  justify-content: flex-end;
  gap: 8px;
  padding: 12px 20px;
  border-top: 1px solid var(--border);
  background: var(--bg-panel);
}

.app-prompt-button {
  min-height: 34px;
  border: 1px solid var(--border);
  border-radius: 6px;
  background: var(--bg);
  color: var(--text);
  cursor: pointer;
  font: inherit;
  font-size: 13px;
  font-weight: 600;
  padding: 7px 13px;
}

.app-prompt-button:hover { background: var(--bg-hover); }
.app-prompt-button:focus-visible { outline: 2px solid var(--accent); outline-offset: 2px; }
.app-prompt-button-primary { border-color: var(--accent); background: var(--accent); color: white; }
.app-prompt-button-primary:hover { background: var(--accent-hover); }
.app-prompt-button-primary.is-danger { border-color: #dc2626; background: #dc2626; }
.app-prompt-button-primary.is-danger:hover { background: #b91c1c; }

@keyframes app-prompt-enter {
  from { opacity: 0; transform: translateY(4px); }
  to { opacity: 1; transform: translateY(0); }
}

@media (max-width: 480px) {
  .app-prompt-overlay { padding: 12px; }
  .app-prompt-dialog { width: calc(100vw - 24px); max-height: calc(100dvh - 24px); }
  .app-prompt-actions { flex-direction: column-reverse; padding: 12px; }
  .app-prompt-button { width: 100%; }
}

@media (prefers-reduced-motion: reduce) {
  .app-prompt-dialog { animation: none; }
}

.app-toast-viewport {
  position: fixed;
  z-index: 1500;
  right: 24px;
  bottom: 24px;
  display: flex;
  width: min(380px, calc(100vw - 24px));
  flex-direction: column-reverse;
  gap: 8px;
  pointer-events: none;
}

.app-toast {
  display: flex;
  align-items: flex-start;
  gap: 10px;
  min-width: 0;
  padding: 10px 10px 10px 14px;
  border: 1px solid var(--border);
  border-left-width: 4px;
  border-radius: 8px;
  background: var(--bg);
  color: var(--text);
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.22);
  pointer-events: auto;
  animation: app-toast-enter 150ms ease-out;
}

.app-toast-success { border-left-color: #16a34a; }
.app-toast-error { border-left-color: #dc2626; }
.app-toast-info { border-left-color: var(--accent); }

.app-toast-message {
  flex: 1;
  min-width: 0;
  overflow-wrap: anywhere;
  font-size: 13px;
  font-weight: 600;
  line-height: 1.45;
}

.app-toast-dismiss {
  width: 24px;
  height: 24px;
  flex: 0 0 24px;
  margin: -2px -2px -2px 0;
  border: 0;
  border-radius: 4px;
  background: transparent;
  color: var(--text-muted);
  cursor: pointer;
  font: inherit;
  font-size: 16px;
  line-height: 1;
}

.app-toast-dismiss:hover { background: var(--bg-hover); color: var(--text); }
.app-toast-dismiss:focus-visible { outline: 2px solid var(--accent); outline-offset: 1px; }

@keyframes app-toast-enter {
  from { opacity: 0; transform: translateY(6px); }
  to { opacity: 1; transform: translateY(0); }
}

@media (max-width: 480px) {
  .app-toast-viewport { right: 12px; bottom: calc(12px + env(safe-area-inset-bottom)); }
}

@media (prefers-reduced-motion: reduce) {
  .app-toast { animation: none; }
}

